#pragma OPENCL EXTENSION cl_khr_fp64 : enable

inline int mirror_index(int d, int sizeD)
{
    if (sizeD <= 1) return 0;
    if (d >= sizeD) {
        d = 2 * sizeD - 2 - d;
    } else if (d < 0) {
        d = -d;
    }
    if (d < 0) d = 0;
    if (d >= sizeD) d = sizeD - 1;
    return d;
}

inline int get_src(__global const int *in, int sx, int sy, int x, int y)
{
    x = mirror_index(x, sx);
    y = mirror_index(y, sy);
    return in[y * sx + x];
}

inline int h_detail(__global const int *in, int sx, int sy, int y, int k)
{
    int x_odd = 2 * k + 1;
    int p = get_src(in, sx, sy, 2 * k, y);
    int c = get_src(in, sx, sy, x_odd, y);
    int n = get_src(in, sx, sy, 2 * k + 2, y);
    return c - ((p + n) / 2);
}

inline int h_low(__global const int *in, int sx, int sy, int y, int k)
{
    const int hlx = sx / 2;
    int c = get_src(in, sx, sy, 2 * k, y);
    if (hlx <= 0) return c;

    int dl = h_detail(in, sx, sy, y, mirror_index(k - 1, hlx));
    int dr = h_detail(in, sx, sy, y, mirror_index(k, hlx));
    return c + ((dl + dr + 2) / 4);
}

inline int h_coeff(__global const int *in, int sx, int sy, int y, int kx, int highBandX)
{
    return highBandX ? h_detail(in, sx, sy, y, kx) : h_low(in, sx, sy, y, kx);
}

inline int v_detail(__global const int *in, int sx, int sy, int kx, int ky, int highBandX)
{
    int c = h_coeff(in, sx, sy, 2 * ky + 1, kx, highBandX);
    int p = h_coeff(in, sx, sy, 2 * ky,     kx, highBandX);
    int n = h_coeff(in, sx, sy, 2 * ky + 2, kx, highBandX);
    return c - ((p + n) / 2);
}

inline int v_low(__global const int *in, int sx, int sy, int kx, int ky, int highBandX)
{
    const int hly = sy / 2;
    int c = h_coeff(in, sx, sy, 2 * ky, kx, highBandX);
    if (hly <= 0) return c;

    int dl = v_detail(in, sx, sy, kx, mirror_index(ky - 1, hly), highBandX);
    int dr = v_detail(in, sx, sy, kx, mirror_index(ky,     hly), highBandX);
    return c + ((dl + dr + 2) / 4);
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    int pixels)
{
    size_t gid = get_global_id(0);
    size_t gsz = get_global_size(0);

    for (int i = (int)gid; i < pixels; i += (int)gsz) {
        int base = i * 3;
        d_r[i] = ((int)d_src[base + 0]) - 128;
        d_g[i] = ((int)d_src[base + 1]) - 128;
        d_b[i] = ((int)d_src[base + 2]) - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   int pixels)
{
    size_t gid = get_global_id(0);
    size_t gsz = get_global_size(0);

    for (int i = (int)gid; i < pixels; i += (int)gsz) {
        d_c[i] = ((int)d_src[i]) - 128;
    }
}

__kernel void cl_fdwt53Kernel(__global const int *input,
                              __global int *output,
                              const int sizeX,
                              const int sizeY,
                              const int winSteps,
                              const int WIN_SX,
                              const int WIN_SY)
{
    (void)winSteps;
    (void)WIN_SX;
    (void)WIN_SY;

    const int llx = (sizeX + 1) / 2;
    const int lly = (sizeY + 1) / 2;
    const int hlx = sizeX / 2;
    const int hly = sizeY / 2;

    const int LLsize = llx * lly;
    const int HLsize = hlx * lly;
    const int LHsize = llx * hly;
    const int total  = sizeX * sizeY;

    size_t gid0 = get_global_id(0);
    size_t gid1 = get_global_id(1);
    size_t gsz0 = get_global_size(0);
    size_t gsz1 = get_global_size(1);

    int tid = (int)(gid1 * gsz0 + gid0);
    int tstride = (int)(gsz0 * gsz1);

    for (int idx = tid; idx < total; idx += tstride) {
        int bandXHigh, bandYHigh;
        int kx, ky;
        int val;

        if (idx < LLsize) {
            bandXHigh = 0; bandYHigh = 0;
            ky = idx / llx;
            kx = idx - ky * llx;
            val = v_low(input, sizeX, sizeY, kx, ky, bandXHigh);
        } else if (idx < LLsize + HLsize) {
            int o = idx - LLsize;
            bandXHigh = 1; bandYHigh = 0;
            ky = (hlx > 0) ? (o / hlx) : 0;
            kx = (hlx > 0) ? (o - ky * hlx) : 0;
            val = v_low(input, sizeX, sizeY, kx, ky, bandXHigh);
        } else if (idx < LLsize + HLsize + LHsize) {
            int o = idx - LLsize - HLsize;
            bandXHigh = 0; bandYHigh = 1;
            ky = (llx > 0) ? (o / llx) : 0;
            kx = (llx > 0) ? (o - ky * llx) : 0;
            (void)bandYHigh;
            val = v_detail(input, sizeX, sizeY, kx, ky, bandXHigh);
        } else {
            int o = idx - LLsize - HLsize - LHsize;
            bandXHigh = 1; bandYHigh = 1;
            ky = (hlx > 0) ? (o / hlx) : 0;
            kx = (hlx > 0) ? (o - ky * hlx) : 0;
            (void)bandYHigh;
            val = v_detail(input, sizeX, sizeY, kx, ky, bandXHigh);
        }

        output[idx] = val;
    }
}
